-- Acts 19 — Ephesus: the Spirit, the Name, and the Silversmiths'' Riot
-- Theme: The Name of the Lord Jesus Magnified

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 19,
  'Acts 19 records Paul''s three-year ministry at Ephesus, the most fruitful and contested of his campaigns. He finds twelve disciples baptized only into John''s baptism; upon hearing of Christ and being baptized in His name, the Spirit comes upon them. Paul reasons three months in the synagogue, then withdraws to the school of Tyrannus, where he lectures daily for two years, so that all Asia hears the word. God works special miracles — handkerchiefs from Paul''s body heal the sick — and the seven sons of Sceva, attempting to exploit the Name, are overpowered by an evil spirit, so that the name of the Lord Jesus is magnified. Many burn their magical books, worth 50,000 pieces of silver. Finally Demetrius, a silversmith whose trade depends on Artemis shrines, stirs the city; a riot fills the theatre for two hours with the cry "Great is Diana of the Ephesians!" The town clerk quiets the crowd with reasoned Roman law. The word of God has so grown and prevailed that the economic engine of pagan worship is shaken to its foundations.',
  'The Name of the Lord Jesus Magnified',
  'ἐμεγαλύνετο',
  'was magnified (emegalyneto) — the name of the Lord Jesus exalted over all competing powers, names, and economies (v.17).',
  '[{"range":"vv.1-7","title":"Twelve Ephesian Disciples: From John''s Baptism to the Holy Spirit"},{"range":"vv.8-10","title":"Synagogue to the School of Tyrannus: Two Years of Daily Teaching"},{"range":"vv.11-20","title":"Special Miracles, the Sons of Sceva, Magic Books Burned"},{"range":"vv.21-22","title":"Paul''s Further Plans: Macedonia, Achaia, Jerusalem, Rome"},{"range":"vv.23-34","title":"Demetrius Stirs the Silversmiths; Riot in the Theatre"},{"range":"vv.35-41","title":"The Town Clerk Disperses the Assembly"}]'::jsonb
FROM books b WHERE b.name = 'Acts'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And it came to pass, that, while Apollos was at Corinth, Paul having passed through the upper coasts came to Ephesus: and finding certain disciples,',
      'Ἐγένετο δὲ ἐν τῷ τὸν Ἀπολλῶ εἶναι ἐν Κορίνθῳ Παῦλον διελθόντα τὰ ἀνωτερικὰ μέρη κατελθεῖν εἰς Ἔφεσον καὶ εὑρεῖν τινας μαθητάς,',
      'Egeneto de en tō ton Apollō einai en Korinthō Paulon dielthonta ta anōterika merē katelthein eis Epheson kai heurein tinas mathētas,',
      'While Apollos labours in Corinth, Paul moves overland through the "upper country" (Phrygian highlands) to the Aegean coast. "Certain disciples" — their status is unclear until further inquiry; they have some knowledge of Christ but incomplete.',
      'Two men, two cities, one Lord — Apollos watering at Corinth, Paul planting at Ephesus, the Spirit giving the increase (1 Cor 3:6).'),
  (2, 'He said unto them, Have ye received the Holy Ghost since ye believed? And they said unto him, We have not so much as heard whether there be any Holy Ghost.',
      'εἶπέν τε πρὸς αὐτούς· Εἰ πνεῦμα ἅγιον ἐλάβετε πιστεύσαντες; οἱ δὲ πρὸς αὐτόν· Ἀλλ᾽ οὐδὲ εἰ πνεῦμα ἅγιον ἔστιν ἠκούσαμεν.',
      'eipen te pros autous; Ei pneuma hagion elabete pisteusantes? hoi de pros auton; All oude ei pneuma hagion estin ēkousamen.',
      'Their reply does not deny Spirit''s existence (the OT they knew speaks often of Him) but confesses ignorance of His Pentecostal descent. They were disciples of John''s preparatory ministry, not yet of the risen and ascended Christ who has poured out the Spirit.',
      'Reception of the Spirit is the hallmark of NT salvation, not an optional second blessing. Wherever faith rests on the ascended Christ, the Spirit is given.'),
  (3, 'And he said unto them, Unto what then were ye baptized? And they said, Unto John''s baptism.',
      'εἶπέν τε· Εἰς τί οὖν ἐβαπτίσθητε; οἱ δὲ εἶπαν· Εἰς τὸ Ἰωάννου βάπτισμα.',
      'eipen te; Eis ti oun ebaptisthēte? hoi de eipan; Eis to Iōannou baptisma.',
      'Paul''s diagnostic question: "into what were ye baptized?" The Christian baptism is "into Christ" (Gal 3:27; Rom 6:3) — theirs was only into John''s preparatory rite of repentance.',
      'The object of baptism determines its meaning. True Christian baptism confesses faith in the crucified, risen, and Spirit-sending Christ.'),
  (4, 'Then said Paul, John verily baptized with the baptism of repentance, saying unto the people, that they should believe on him which should come after him, that is, on Christ Jesus.',
      'εἶπεν δὲ Παῦλος· Ἰωάννης ἐβάπτισεν βάπτισμα μετανοίας, τῷ λαῷ λέγων εἰς τὸν ἐρχόμενον μετ᾽ αὐτὸν ἵνα πιστεύσωσιν, τοῦτ᾽ ἔστιν εἰς τὸν Ἰησοῦν.',
      'eipen de Paulos; Iōannēs ebaptisen baptisma metanoias, tō laō legōn eis ton erchomenon met auton hina pisteusōsin, tout estin eis ton Iēsoun.',
      'John''s own preaching pointed forward to One greater (Luke 3:16). Paul''s brief summary places Jesus as the fulfilled object of John''s forward-looking message.',
      'The old covenant points to Christ; the new covenant rests in Him. Any message that stops at repentance without arriving at faith in Jesus is incomplete.'),
  (5, 'When they heard this, they were baptized in the name of the Lord Jesus.',
      'ἀκούσαντες δὲ ἐβαπτίσθησαν εἰς τὸ ὄνομα τοῦ κυρίου Ἰησοῦ.',
      'akousantes de ebaptisthēsan eis to onoma tou kyriou Iēsou.',
      'Baptism "into the name of the Lord Jesus" — the only instance of explicit rebaptism in the NT, because the earlier baptism was into an incomplete revelation. The baptismal formula names Jesus as the Lord of the new covenant.',
      'Christian baptism belongs to the name of Jesus. Where faith comes to Christ more fully than before, baptism into His name is the natural consequence.'),
  (6, 'And when Paul had laid his hands upon them, the Holy Ghost came on them; and they spake with tongues, and prophesied.',
      'καὶ ἐπιθέντος αὐτοῖς τοῦ Παύλου τὰς χεῖρας ἦλθεν τὸ πνεῦμα τὸ ἅγιον ἐπ᾽ αὐτούς, ἐλάλουν τε γλώσσαις καὶ ἐπροφήτευον.',
      'kai epithentos autois tou Paulou tas cheiras ēlthen to pneuma to hagion ep autous, elaloun te glōssais kai eprophēteuon.',
      'Laying on of hands mediates the apostolic recognition. Tongues and prophecy are the visible sign — the Ephesian "Pentecost" parallels the Jerusalem, Samaritan (8:17), and Caesarean (10:46) ones, bringing the remaining OT category (disciples of John) fully into the new covenant.',
      'God graciously gave public sign-manifestations at each major frontier of the Spirit''s outpouring. The uniform grace has a uniform witness, binding the one church across every former barrier.'),
  (7, 'And all the men were about twelve.',
      'ἦσαν δὲ οἱ πάντες ἄνδρες ὡσεὶ δώδεκα.',
      'ēsan de hoi pantes andres hōsei dōdeka.',
      'The number twelve is suggestive but not symbolic — Luke says "about twelve." They are a remnant of John''s disciples now fully folded into the Christian church.',
      'Every disciple belongs either to the still-incomplete gospel or to the fulfilled one. Christ completes what John announced.'),
  (8, 'And he went into the synagogue, and spake boldly for the space of three months, disputing and persuading the things concerning the kingdom of God.',
      'Εἰσελθὼν δὲ εἰς τὴν συναγωγὴν ἐπαρρησιάζετο ἐπὶ μῆνας τρεῖς διαλεγόμενος καὶ πείθων περὶ τῆς βασιλείας τοῦ θεοῦ.',
      'Eiselthōn de eis tēn synagōgēn eparrēsiazeto epi mēnas treis dialegomenos kai peithōn peri tēs basileias tou theou.',
      'Three months, a longer synagogue tenure than anywhere else — evidence of initial Ephesian openness. Paul''s theme is "the kingdom of God" — the reign inaugurated by Christ''s resurrection (28:31).',
      'The gospel is the message of the kingdom of God in Christ. Where rightly preached, it always seeks persuasion, not mere declaration.'),
  (9, 'But when divers were hardened, and believed not, but spake evil of that way before the multitude, he departed from them, and separated the disciples, disputing daily in the school of one Tyrannus.',
      'ὡς δέ τινες ἐσκληρύνοντο καὶ ἠπείθουν κακολογοῦντες τὴν ὁδὸν ἐνώπιον τοῦ πλήθους, ἀποστὰς ἀπ᾽ αὐτῶν ἀφώρισεν τοὺς μαθητάς, καθ᾽ ἡμέραν διαλεγόμενος ἐν τῇ σχολῇ Τυράννου.',
      'hōs de tines esklērynonto kai ēpeithoun kakologountes tēn hodon enōpion tou plēthous, apostas ap autōn aphōrisen tous mathētas, kath hēmeran dialegomenos en tē scholē Tyrannou.',
      '"That way" — the Christian movement''s self-designation (cf. 9:2). Schole Tyrannou — a public lecture hall rented for instruction. Some texts add "from the fifth to the tenth hour" (11am-4pm) — the siesta when the hall was idle and people free.',
      'Where hearts harden, the apostle separates disciples without bitterness. Ongoing teaching is the backbone of every enduring church.'),
  (10, 'And this continued by the space of two years; so that all they which dwelt in Asia heard the word of the Lord Jesus, both Jews and Greeks.',
      'τοῦτο δὲ ἐγένετο ἐπὶ ἔτη δύο, ὥστε πάντας τοὺς κατοικοῦντας τὴν Ἀσίαν ἀκοῦσαι τὸν λόγον τοῦ κυρίου, Ἰουδαίους τε καὶ Ἕλληνας.',
      'touto de egeneto epi etē dyo, hōste pantas tous katoikountas tēn Asian akousai ton logon tou kyriou, Ioudaious te kai Hellēnas.',
      '"All Asia" — the Roman province of western Asia Minor. From Ephesus as hub, converts fanned out to evangelise Colossae, Laodicea, Hierapolis (Col 1:7; 4:13), and possibly other of the Seven Churches of Rev 2-3.',
      'God uses strategic cities as megaphones of the gospel. Faithful ministry in a regional capital echoes through every surrounding town.'),
  (11, 'And God wrought special miracles by the hands of Paul:',
      'Δυνάμεις τε οὐ τὰς τυχούσας ὁ θεὸς ἐποίει διὰ τῶν χειρῶν Παύλου,',
      'Dynameis te ou tas tychousas ho theos epoiei dia tōn cheirōn Paulou,',
      'Ou tas tychousas — literally "not the ordinary ones," extraordinary miracles. Ephesus was the world-capital of magic; God''s power must visibly transcend theirs.',
      'Where occult powers are strongest, God often shows His supremacy most openly. Special circumstances call for extraordinary confirmations of the true gospel.'),
  (12, 'So that from his body were brought unto the sick handkerchiefs or aprons, and the diseases departed from them, and the evil spirits went out of them.',
      'ὥστε καὶ ἐπὶ τοὺς ἀσθενοῦντας ἀποφέρεσθαι ἀπὸ τοῦ χρωτὸς αὐτοῦ σουδάρια ἢ σιμικίνθια καὶ ἀπαλλάσσεσθαι ἀπ᾽ αὐτῶν τὰς νόσους, τά τε πνεύματα τὰ πονηρὰ ἐκπορεύεσθαι.',
      'hōste kai epi tous asthenountas apopheresthai apo tou chrōtos autou soudaria ē simikinthia kai apallassesthai ap autōn tas nosous, ta te pneumata ta ponēra ekporeuesthai.',
      'Soudaria (sweat-cloths) and simikinthia (work-aprons) — items from Paul''s tentmaking trade, carried to the sick. Not magical amulets; rather, tokens of apostolic authority.',
      'God condescends to human need by tangible means. The virtue is His, not the cloth''s — yet He graciously uses physical means to confirm His word.'),
  (13, 'Then certain of the vagabond Jews, exorcists, took upon them to call over them which had evil spirits the name of the Lord Jesus, saying, We adjure you by Jesus whom Paul preacheth.',
      'Ἐπεχείρησαν δέ τινες καὶ τῶν περιερχομένων Ἰουδαίων ἐξορκιστῶν ὀνομάζειν ἐπὶ τοὺς ἔχοντας τὰ πνεύματα τὰ πονηρὰ τὸ ὄνομα τοῦ κυρίου Ἰησοῦ λέγοντες· Ὁρκίζω ὑμᾶς τὸν Ἰησοῦν ὃν Παῦλος κηρύσσει.',
      'Epecheirēsan de tines kai tōn perierchomenōn Ioudaiōn exorkistōn onomazein epi tous echontas ta pneumata ta ponēra to onoma tou kyriou Iēsou legontes; Horkizō hymas ton Iēsoun hon Paulos kēryssei.',
      'Itinerant Jewish exorcists exploit Jesus'' name as magical formula. "Jesus whom Paul preacheth" — they invoke it secondhand, without personal faith.',
      'The Name of Christ is not a magical charm to be manipulated. Power flows where faith flows; where faith is absent, the Name burns the borrower.'),
  (14, 'And there were seven sons of one Sceva, a Jew, and chief of the priests, which did so.',
      'ἦσαν δέ τινος Σκευᾶ Ἰουδαίου ἀρχιερέως ἑπτὰ υἱοὶ τοῦτο ποιοῦντες.',
      'ēsan de tinos Skeua Ioudaiou archiereōs hepta huioi touto poiountes.',
      'Sceva is called "chief priest" — likely a self-styled title or a member of a chief-priestly family exiled from Jerusalem. The seven sons made their living by exorcism.',
      'Religious pedigree gives no power without personal faith. Seven sons of a priestly house cannot conjure what one believing apostle exercises.'),
  (15, 'And the evil spirit answered and said, Jesus I know, and Paul I know; but who are ye?',
      'ἀποκριθὲν δὲ τὸ πνεῦμα τὸ πονηρὸν εἶπεν αὐτοῖς· Τὸν Ἰησοῦν γινώσκω καὶ τὸν Παῦλον ἐπίσταμαι, ὑμεῖς δὲ τίνες ἐστέ;',
      'apokrithen de to pneuma to ponēron eipen autois; Ton Iēsoun ginōskō kai ton Paulon epistamai, hymeis de tines este?',
      'The demon knows Jesus by a full knowing (ginōskō — relational knowledge of the Conqueror) and Paul by acquaintance (epistamai — personal knowledge of the ambassador), but not the sons. The indictment is devastating.',
      'Hell knows who belongs to Christ. The demon respects only a Name it has met on its own field — and a man who bears that Name by true faith.'),
  (16, 'And the man in whom the evil spirit was leaped on them, and overcame them, and prevailed against them, so that they fled out of that house naked and wounded.',
      'καὶ ἐφαλόμενος ὁ ἄνθρωπος ἐπ᾽ αὐτοὺς ἐν ᾧ ἦν τὸ πνεῦμα τὸ πονηρὸν κατακυριεύσας ἀμφοτέρων ἴσχυσεν κατ᾽ αὐτῶν, ὥστε γυμνοὺς καὶ τετραυματισμένους ἐκφυγεῖν ἐκ τοῦ οἴκου ἐκείνου.',
      'kai ephalomenos ho anthrōpos ep autous en hō ēn to pneuma to ponēron katakyrieusas amphoterōn ischysen kat autōn, hōste gymnous kai tetraumatismenous ekphygein ek tou oikou ekeinou.',
      'Amphoterōn, "both," probably meaning all of them collectively (NT Greek sometimes uses it of more than two). They flee stripped and wounded — the opposite of the liberation the gospel brings.',
      'The Name abused humiliates those who wield it falsely. When grace is treated as technique, it turns against the trickster.'),
  (17, 'And this was known to all the Jews and Greeks also dwelling at Ephesus; and fear fell on them all, and the name of the Lord Jesus was magnified.',
      'τοῦτο δὲ ἐγένετο γνωστὸν πᾶσιν Ἰουδαίοις τε καὶ Ἕλλησιν τοῖς κατοικοῦσιν τὴν Ἔφεσον, καὶ ἐπέπεσεν φόβος ἐπὶ πάντας αὐτούς, καὶ ἐμεγαλύνετο τὸ ὄνομα τοῦ κυρίου Ἰησοῦ.',
      'touto de egeneto gnōston pasin Ioudaiois te kai Hellēsin tois katoikousin tēn Epheson, kai epepesen phobos epi pantas autous, kai emegalyneto to onoma tou kyriou Iēsou.',
      'Emegalyneto — "was magnified." The failed exorcism paradoxically exalts Christ''s name; it alone carries real authority, and only true believers bear it rightly.',
      'God magnifies the name of Christ by rebuking those who counterfeit it. Even failed attempts to use Christ''s name without faith serve His glory.'),
  (18, 'And many that believed came, and confessed, and shewed their deeds.',
      'Πολλοί τε τῶν πεπιστευκότων ἤρχοντο ἐξομολογούμενοι καὶ ἀναγγέλλοντες τὰς πράξεις αὐτῶν.',
      'Polloi te tōn pepisteukotōn ērchonto exomologoumenoi kai anangellontes tas praxeis autōn.',
      'The magnifying of Christ''s name drives believers to confession. Some had evidently held onto residual occult practices; revival exposes secret sins.',
      'True revival shines into every corner. Renewed fear of God produces plain confession and practical renunciation of hidden compromises.'),
  (19, 'Many of them also which used curious arts brought their books together, and burned them before all men: and they counted the price of them, and found it fifty thousand pieces of silver.',
      'ἱκανοὶ δὲ τῶν τὰ περίεργα πραξάντων συνενέγκαντες τὰς βίβλους κατέκαιον ἐνώπιον πάντων· καὶ συνεψήφισαν τὰς τιμὰς αὐτῶν καὶ εὗρον ἀργυρίου μυριάδας πέντε.',
      'hikanoi de tōn ta perierga praxantōn synenenkantes tas biblous katekaion enōpion pantōn; kai synepsēphisan tas timas autōn kai heuron argyriou myriadas pente.',
      '"Curious arts" (perierga) = magical and occult practices. Ephesus was famous for magical texts (the "Ephesian writings," Ephesia grammata). Fifty thousand silver drachmas = roughly 50,000 days'' wages — an enormous public destruction of valuable property.',
      'Genuine conversion costs. Burning magical books is visible, expensive repudiation of the old life — the pattern for every true convert who carries idolatrous things from his past.'),
  (20, 'So mightily grew the word of God and prevailed.',
      'οὕτως κατὰ κράτος τοῦ κυρίου ὁ λόγος ηὔξανεν καὶ ἴσχυεν.',
      'houtōs kata kratos tou kyriou ho logos ēuxanen kai ischyen.',
      'One of Luke''s recurring progress reports (cf. 6:7; 12:24). "Mightily" (kata kratos) is a military metaphor — the word advances as a conquering force.',
      'The preached word, when truly the Lord''s, grows and prevails. Nothing the world, flesh, or Satan throws at it can ultimately stop its advance.'),
  (21, 'After these things were ended, Paul purposed in the spirit, when he had passed through Macedonia and Achaia, to go to Jerusalem, saying, After I have been there, I must also see Rome.',
      'Ὡς δὲ ἐπληρώθη ταῦτα, ἔθετο ὁ Παῦλος ἐν τῷ πνεύματι διελθὼν τὴν Μακεδονίαν καὶ Ἀχαΐαν πορεύεσθαι εἰς Ἱεροσόλυμα εἰπών· Ὅτι μετὰ τὸ γενέσθαι με ἐκεῖ δεῖ με καὶ Ῥώμην ἰδεῖν.',
      'Hōs de eplērōthē tauta, etheto ho Paulos en tō pneumati dielthōn tēn Makedonian kai Achaian poreuesthai eis Hierosolyma eipōn; Hoti meta to genesthai me ekei dei me kai Rhōmēn idein.',
      '"I must see Rome" (dei) — divine necessity. Rome was the heart of the empire, the natural terminus of apostolic witness to the Gentiles. The remainder of Acts (20-28) narrates the journey to Rome in chains.',
      'The apostle''s ambitions are shaped by divine imperative, not mere human planning. The Lord''s "must" becomes the servant''s commitment.'),
  (22, 'So he sent into Macedonia two of them that ministered unto him, Timotheus and Erastus; but he himself stayed in Asia for a season.',
      'ἀποστείλας δὲ εἰς τὴν Μακεδονίαν δύο τῶν διακονούντων αὐτῷ, Τιμόθεον καὶ Ἔραστον, αὐτὸς ἐπέσχεν χρόνον εἰς τὴν Ἀσίαν.',
      'aposteilas de eis tēn Makedonian dyo tōn diakonountōn autō, Timotheon kai Eraston, autos epeschen chronon eis tēn Asian.',
      'Erastus is possibly the Corinthian city treasurer (Rom 16:23); Timothy is Paul''s faithful young lieutenant. They are sent ahead to prepare the collection for Jerusalem (1 Cor 16; 2 Cor 8-9).',
      'The apostle delegates. Ministry is team-work; God grows leaders by entrusting them with real responsibility in the master''s absence.'),
  (23, 'And the same time there arose no small stir about that way.',
      'Ἐγένετο δὲ κατὰ τὸν καιρὸν ἐκεῖνον τάραχος οὐκ ὀλίγος περὶ τῆς ὁδοῦ.',
      'Egeneto de kata ton kairon ekeinon tarachos ouk oligos peri tēs hodou.',
      'Litotes — "no small stir" = a great uproar. "That way" again = the Christian movement.',
      'The gospel''s success creates opposition proportionate to its impact. Where Christ dethrones an economic idol, the city shakes.'),
  (24, 'For a certain man named Demetrius, a silversmith, which made silver shrines for Diana, brought no small gain unto the craftsmen;',
      'Δημήτριος γάρ τις ὀνόματι, ἀργυροκόπος, ποιῶν ναοὺς ἀργυροῦς Ἀρτέμιδος παρείχετο τοῖς τεχνίταις οὐκ ὀλίγην ἐργασίαν,',
      'Dēmētrios gar tis onomati, argyrokopos, poiōn naous argyrous Artemidos pareicheto tois technitais ouk oligēn ergasian,',
      'Silver shrines — miniature models of the Artemision (temple of Artemis/Diana), one of the Seven Wonders of the Ancient World, sold as souvenirs. Demetrius is a craft-guild leader whose business the gospel is destroying.',
      'Mammon and idolatry are perpetual partners. When Christ threatens profit built on false worship, the idol''s friends reveal themselves.'),
  (25, 'Whom he called together with the workmen of like occupation, and said, Sirs, ye know that by this craft we have our wealth.',
      'οὓς συναθροίσας καὶ τοὺς περὶ τὰ τοιαῦτα ἐργάτας εἶπεν· Ἄνδρες, ἐπίστασθε ὅτι ἐκ ταύτης τῆς ἐργασίας ἡ εὐπορία ἡμῖν ἐστιν,',
      'hous synathroisas kai tous peri ta toiauta ergatas eipen; Andres, epistasthe hoti ek tautēs tēs ergasias hē euporia hēmin estin,',
      'Demetrius is frank: the issue is economic. Euporia, "prosperity." The defense of Artemis is cover for the defense of revenue.',
      'Attacks on the gospel frequently dress up economic self-interest as religious zeal. Follow the money and you often find the true motive.'),
  (26, 'Moreover ye see and hear, that not alone at Ephesus, but almost throughout all Asia, this Paul hath persuaded and turned away much people, saying that they be no gods, which are made with hands:',
      'καὶ θεωρεῖτε καὶ ἀκούετε ὅτι οὐ μόνον Ἐφέσου ἀλλὰ σχεδὸν πάσης τῆς Ἀσίας ὁ Παῦλος οὗτος πείσας μετέστησεν ἱκανὸν ὄχλον λέγων ὅτι οὐκ εἰσὶν θεοὶ οἱ διὰ χειρῶν γινόμενοι.',
      'kai theōreite kai akouete hoti ou monon Ephesou alla schedon pasēs tēs Asias ho Paulos houtos peisas metestēsen hikanon ochlon legōn hoti ouk eisin theoi hoi dia cheirōn ginomenoi.',
      'The enemy acknowledges what Luke has been asserting (v.10) — Paul''s ministry has reached "almost all Asia." Demetrius summarises the gospel accurately: "they be no gods which are made with hands."',
      'The gospel''s slanderers often summarise it better than its friends. When enemies report the wide impact, it testifies that the word has grown mightily.'),
  (27, 'So that not only this our craft is in danger to be set at nought; but also that the temple of the great goddess Diana should be despised, and her magnificence should be destroyed, whom all Asia and the world worshippeth.',
      'οὐ μόνον δὲ τοῦτο κινδυνεύει ἡμῖν τὸ μέρος εἰς ἀπελεγμὸν ἐλθεῖν, ἀλλὰ καὶ τὸ τῆς μεγάλης θεᾶς Ἀρτέμιδος ἱερὸν εἰς οὐθὲν λογισθῆναι, μέλλειν τε καὶ καθαιρεῖσθαι τῆς μεγαλειότητος αὐτῆς, ἣν ὅλη ἡ Ἀσία καὶ ἡ οἰκουμένη σέβεται.',
      'ou monon de touto kindyneuei hēmin to meros eis apelegmon elthein, alla kai to tēs megalēs theas Artemidos hieron eis outhen logisthēnai, mellein te kai kathaireisthai tēs megaleiotētos autēs, hēn holē hē Asia kai hē oikoumenē sebetai.',
      'Demetrius cleverly redirects focus from profits (his real concern) to the goddess''s honour (the crowd''s passion). Artemis of Ephesus was a fertility-goddess with a multi-breasted cult image, her temple 4× the size of the Parthenon.',
      'Idolatry wraps its commercial interests in sacred language to rally mobs. The Christian must discern the real motive behind pious outrage.'),
  (28, 'And when they heard these sayings, they were full of wrath, and cried out, saying, Great is Diana of the Ephesians.',
      'Ἀκούσαντες δὲ καὶ γενόμενοι πλήρεις θυμοῦ ἔκραζον λέγοντες· Μεγάλη ἡ Ἄρτεμις Ἐφεσίων.',
      'Akousantes de kai genomenoi plēreis thymou ekrazon legontes; Megalē hē Artemis Ephesiōn.',
      '"Great is Diana!" — a well-attested ancient acclamation (found in Ephesian inscriptions). The cry is both religious and civic; Artemis and Ephesus are identified.',
      'Mob cries are sincere, loud, and wrong. Volume is not truth; crowd acclamation cannot make a man-made goddess divine.'),
  (29, 'And the whole city was filled with confusion: and having caught Gaius and Aristarchus, men of Macedonia, Paul''s companions in travel, they rushed with one accord into the theatre.',
      'καὶ ἐπλήσθη ἡ πόλις τῆς συγχύσεως, ὥρμησάν τε ὁμοθυμαδὸν εἰς τὸ θέατρον, συναρπάσαντες Γάϊον καὶ Ἀρίσταρχον Μακεδόνας, συνεκδήμους Παύλου.',
      'kai eplēsthē hē polis tēs sygchyseōs, hōrmēsan te homothymadon eis to theatron, synarpasantes Gaion kai Aristarchon Makedonas, synekdēmous Paulou.',
      'The Ephesian theatre seated 24,000 — its ruins still stand. Gaius and Aristarchus, Macedonian companions (20:4; 27:2), are seized as Paul''s proxies.',
      'Faithful companions share their leader''s danger. The apostolate is a fellowship of risk, not merely of service.'),
  (30, 'And when Paul would have entered in unto the people, the disciples suffered him not.',
      'Παύλου δὲ βουλομένου εἰσελθεῖν εἰς τὸν δῆμον οὐκ εἴων αὐτὸν οἱ μαθηταί·',
      'Paulou de boulomenou eiselthein eis ton dēmon ouk eiōn auton hoi mathētai;',
      'Paul would have faced the 24,000-strong mob personally. The disciples hold him back — love restraining reckless zeal.',
      'The church''s love sometimes guards the apostle from his own courage. Bold men need wise brethren to check untimely heroism.'),
  (31, 'And certain of the chief of Asia, which were his friends, sent unto him, desiring him that he would not adventure himself into the theatre.',
      'τινὲς δὲ καὶ τῶν Ἀσιαρχῶν, ὄντες αὐτῷ φίλοι, πέμψαντες πρὸς αὐτὸν παρεκάλουν μὴ δοῦναι ἑαυτὸν εἰς τὸ θέατρον.',
      'tines de kai tōn Asiarchōn, ontes autō philoi, pempsantes pros auton parekaloun mē dounai heauton eis to theatron.',
      'Asiarchs — high-ranking provincial officials supervising imperial cult and games in Asia. That such men were Paul''s friends shows the gospel had penetrated the ruling class without compromising them.',
      'Christ has friends in high places whom He raises up as protectors of His servants. The quiet influence of believing officials shields what outright opposition would destroy.'),
  (32, 'Some therefore cried one thing, and some another: for the assembly was confused; and the more part knew not wherefore they were come together.',
      'ἄλλοι μὲν οὖν ἄλλο τι ἔκραζον, ἦν γὰρ ἡ ἐκκλησία συγκεχυμένη, καὶ οἱ πλείους οὐκ ᾔδεισαν τίνος ἕνεκα συνεληλύθεισαν.',
      'alloi men oun allo ti ekrazon, ēn gar hē ekklēsia sygkechymenē, kai hoi pleious ouk ēdeisan tinos heneka synelēlytheisan.',
      'Luke wryly uses ekklēsia ("assembly") of this pagan mob — the same word usually translated "church." Note that most of the crowd didn''t even know why they were there.',
      'Fear and confusion are Satan''s crowd-control tools. The mob that persecutes Christians is almost always as ignorant as it is furious.'),
  (33, 'And they drew Alexander out of the multitude, the Jews putting him forward. And Alexander beckoned with the hand, and would have made his defence unto the people.',
      'ἐκ δὲ τοῦ ὄχλου συνεβίβασαν Ἀλέξανδρον, προβαλλόντων αὐτὸν τῶν Ἰουδαίων· ὁ δὲ Ἀλέξανδρος κατασείσας τὴν χεῖρα ἤθελεν ἀπολογεῖσθαι τῷ δήμῳ.',
      'ek de tou ochlou synebibasan Alexandron, proballontōn auton tōn Ioudaiōn; ho de Alexandros kataseisas tēn cheira ēthelen apologeisthai tō dēmō.',
      'The Jews push Alexander forward, presumably to distinguish Judaism from Christianity and deflect the mob''s wrath. (Whether this is the Alexander of 1 Tim 1:20 or 2 Tim 4:14 is uncertain.)',
      'When the gospel is under attack, false religions distance themselves from Christ rather than defend His people. The world sees through such self-preservation.'),
  (34, 'But when they knew that he was a Jew, all with one voice about the space of two hours cried out, Great is Diana of the Ephesians.',
      'ἐπιγνόντες δὲ ὅτι Ἰουδαῖός ἐστιν φωνὴ ἐγένετο μία ἐκ πάντων ὡς ἐπὶ ὥρας δύο κραζόντων· Μεγάλη ἡ Ἄρτεμις Ἐφεσίων.',
      'epignontes de hoti Ioudaios estin phōnē egeneto mia ek pantōn hōs epi hōras dyo krazontōn; Megalē hē Artemis Ephesiōn.',
      'Two hours of monotonous chanting — the physical exhaustion of idolatrous frenzy. The Jew''s attempt to speak inflames the anti-Semitic mob further.',
      'Religious mobs are capable of prolonged, senseless repetition. The louder idolatry cries, the more empty it proves.'),
  (35, 'And when the townclerk had appeased the people, he said, Ye men of Ephesus, what man is there that knoweth not how that the city of the Ephesians is a worshipper of the great goddess Diana, and of the image which fell down from Jupiter?',
      'καταστείλας δὲ τὸν ὄχλον ὁ γραμματεὺς φησίν· Ἄνδρες Ἐφέσιοι, τίς γάρ ἐστιν ἀνθρώπων ὃς οὐ γινώσκει τὴν Ἐφεσίων πόλιν νεωκόρον οὖσαν τῆς μεγάλης Ἀρτέμιδος καὶ τοῦ διοπετοῦς;',
      'katasteilas de ton ochlon ho grammateus phēsin; Andres Ephesioi, tis gar estin anthrōpōn hos ou ginōskei tēn Ephesiōn polin neōkoron ousan tēs megalēs Artemidos kai tou diopetous?',
      'The grammateus (town clerk) was the chief civic official, accountable to Rome. Neōkoron ("temple-warden") was an honorary title. "Fell from Jupiter" (diopetous) — meteoric stone worshipped as divine, common pagan belief.',
      'Providence uses even pagan civic order to protect the church. When the gospel''s advance shakes a city, God raises up calm voices to cool illegal violence.'),
  (36, 'Seeing then that these things cannot be spoken against, ye ought to be quiet, and to do nothing rashly.',
      'ἀναντιρρήτων οὖν ὄντων τούτων δέον ἐστὶν ὑμᾶς κατεσταλμένους ὑπάρχειν καὶ μηδὲν προπετὲς πράσσειν.',
      'anantirrētōn oun ontōn toutōn deon estin hymas katestalmenous hyparchein kai mēden propetes prassein.',
      '"Cannot be spoken against" is ironic — the clerk assumes Artemis''s greatness but Paul has just disproved it. Yet the logic serves: if Ephesus''s status is secure, there is no need for riot.',
      'Civic order is God''s provision for the church''s protection. Even a pagan''s appeal to reason can still the enemy''s rage.'),
  (37, 'For ye have brought hither these men, which are neither robbers of churches, nor yet blasphemers of your goddess.',
      'ἠγάγετε γὰρ τοὺς ἄνδρας τούτους οὔτε ἱεροσύλους οὔτε βλασφημοῦντας τὴν θεὸν ἡμῶν.',
      'ēgagete gar tous andras toutous oute hierosylous oute blasphēmountas tēn theon hēmōn.',
      'The apostles have not stolen from temples or insulted the goddess directly (cf. Paul''s prudent method in Athens and before Felix). They preached Christ; the idols fell by implication.',
      'The Christian witness in a pagan culture is positive proclamation of Christ, not direct assault on other gods. Grace is more powerful than polemic.'),
  (38, 'Wherefore if Demetrius, and the craftsmen which are with him, have a matter against any man, the law is open, and there are deputies: let them implead one another.',
      'εἰ μὲν οὖν Δημήτριος καὶ οἱ σὺν αὐτῷ τεχνῖται ἔχουσιν πρός τινα λόγον, ἀγοραῖοι ἄγονται καὶ ἀνθύπατοί εἰσιν, ἐγκαλείτωσαν ἀλλήλοις.',
      'ei men oun Dēmētrios kai hoi syn autō technitai echousin pros tina logon, agoraioi agontai kai anthypatoi eisin, enkaleitōsan allēlois.',
      '"The law is open" (agoraioi = court days) — the town clerk directs grievances to legitimate legal channels. "Deputies" (anthypatoi, plural, though Asia had one proconsul at a time) — a formal appeal to rule of law.',
      'The rule of law is God''s mercy to a fallen world. The church should be the first to respect it, and the last to excuse mob rule.'),
  (39, 'But if ye enquire any thing concerning other matters, it shall be determined in a lawful assembly.',
      'εἰ δέ τι περαιτέρω ἐπιζητεῖτε, ἐν τῇ ἐννόμῳ ἐκκλησίᾳ ἐπιλυθήσεται.',
      'ei de ti peraiterō epizēteite, en tē ennomō ekklēsia epilythēsetai.',
      '"Lawful assembly" (ennomō ekklēsia) — the regular civic council, distinct from the present mob.',
      'Truth is best decided by ordered counsel, not by crowd passion. The church prospers where legal assembly replaces mob.'),
  (40, 'For we are in danger to be called in question for this day''s uproar, there being no cause whereby we may give an account of this concourse.',
      'καὶ γὰρ κινδυνεύομεν ἐγκαλεῖσθαι στάσεως περὶ τῆς σήμερον, μηδενὸς αἰτίου ὑπάρχοντος, περὶ οὗ οὐ δυνησόμεθα δοῦναι λόγον περὶ τῆς συστροφῆς ταύτης.',
      'kai gar kindyneuomen enkaleisthai staseōs peri tēs sēmeron, mēdenos aitiou hyparchontos, peri hou ou dynēsometha dounai logon peri tēs systrophēs tautēs.',
      'Cities under Roman rule could lose privileges for public disturbance. The clerk warns of imperial consequences.',
      'Wisdom weighs consequences. A city shaking itself loose from Rome''s favour is as foolish as a mob shaking itself loose from Christ''s peace.'),
  (41, 'And when he had thus spoken, he dismissed the assembly.',
      'καὶ ταῦτα εἰπὼν ἀπέλυσεν τὴν ἐκκλησίαν.',
      'kai tauta eipōn apelysen tēn ekklēsian.',
      'The riot dissolves. The apostles are safe; the gospel continues.',
      'The Lord stills the storm through every instrument He pleases — angels, magistrates, or town clerks. His providence preserves His servants to the last.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Acts' AND c.chapter_number = 19
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (2, 'πνεῦμα ἅγιον', 'pneuma hagion', 'G4151/G40', 'Holy Spirit — the Pentecostal gift, new-covenant indwelling.', 1),
  (3, 'Ἰωάννου βάπτισμα', 'Iōannou baptisma', 'G2491/G908', 'John''s baptism — preparatory rite of repentance only.', 2),
  (5, 'εἰς τὸ ὄνομα', 'eis to onoma', 'G3686', 'Into the name — baptism appropriating the authority and covenant of Jesus.', 3),
  (6, 'ἐπιθέντος τὰς χεῖρας', 'epithentos tas cheiras', 'G2007/G5495', 'Having laid on hands — apostolic mediation of Spirit-reception.', 4),
  (6, 'γλώσσαις', 'glōssais', 'G1100', 'Tongues — supernatural foreign languages as sign of the Spirit''s coming.', 5),
  (8, 'ἐπαρρησιάζετο', 'eparrēsiazeto', 'G3955', 'Was speaking boldly — Spirit-given freedom of speech.', 6),
  (8, 'βασιλείας τοῦ θεοῦ', 'basileias tou theou', 'G932/G2316', 'Kingdom of God — the reign inaugurated in Christ.', 7),
  (9, 'ἐσκληρύνοντο', 'esklērynonto', 'G4645', 'Were being hardened — progressive judicial hardening through rejection.', 8),
  (9, 'ὁδὸν', 'hodon', 'G3598', 'Way — early Christian self-designation (cf. 9:2; 24:14).', 9),
  (9, 'σχολῇ Τυράννου', 'scholē Tyrannou', 'G4981/G5181', 'School of Tyrannus — rented lecture hall for daily public teaching.', 10),
  (10, 'πάντας τοὺς κατοικοῦντας τὴν Ἀσίαν', 'pantas tous katoikountas tēn Asian', 'G3956/G2730/G773', 'All inhabitants of Asia — the word radiated regionally from Ephesus.', 11),
  (11, 'δυνάμεις οὐ τὰς τυχούσας', 'dynameis ou tas tychousas', 'G1411/G5177', 'Extraordinary miracles — unusual power-works, not the ordinary kind.', 12),
  (12, 'σουδάρια', 'soudaria', 'G4676', 'Sweat-cloths, handkerchiefs — ordinary items made conduits of healing.', 13),
  (12, 'σιμικίνθια', 'simikinthia', 'G4612', 'Work-aprons — used by tradesmen, here Paul''s tentmaking garments.', 14),
  (13, 'ἐξορκιστῶν', 'exorkistōn', 'G1845', 'Exorcists — itinerant practitioners of ritual adjuration.', 15),
  (13, 'ὁρκίζω', 'horkizō', 'G3726', 'I adjure — formal oath-binding invocation.', 16),
  (14, 'Σκευᾶ', 'Skeua', 'G4630', 'Sceva — self-styled "chief priest," father of seven exorcist sons.', 17),
  (15, 'γινώσκω', 'ginōskō', 'G1097', 'I know (relationally) — the demon knows Jesus as conqueror.', 18),
  (15, 'ἐπίσταμαι', 'epistamai', 'G1987', 'I am acquainted with — knowledge of Paul as Jesus'' agent.', 19),
  (16, 'κατακυριεύσας', 'katakyrieusas', 'G2634', 'Overpowered, mastered — the demon''s decisive dominance.', 20),
  (17, 'ἐμεγαλύνετο', 'emegalyneto', 'G3170', 'Was magnified — the key verb of the chapter; Christ''s name exalted.', 21),
  (18, 'ἐξομολογούμενοι', 'exomologoumenoi', 'G1843', 'Openly confessing — full public acknowledgment of sin.', 22),
  (19, 'περίεργα', 'perierga', 'G4021', 'Curious arts — magical and occult practices.', 23),
  (19, 'μυριάδας πέντε', 'myriadas pente', 'G3461/G4002', 'Fifty thousand — drachma pieces; an enormous sum for a book-burning.', 24),
  (20, 'κατὰ κράτος', 'kata kratos', 'G2596/G2904', 'According to might — military metaphor of the word''s prevailing.', 25),
  (20, 'ηὔξανεν', 'ēuxanen', 'G837', 'Was growing — the word as living organism (cf. 6:7; 12:24).', 26),
  (21, 'ἔθετο ἐν τῷ πνεύματι', 'etheto en tō pneumati', 'G5087/G4151', 'Purposed in the spirit — Spirit-led resolve toward Jerusalem and Rome.', 27),
  (21, 'δεῖ', 'dei', 'G1163', 'It is necessary — divine imperative for Rome.', 28),
  (22, 'διακονούντων', 'diakonountōn', 'G1247', 'Ministering — active service of apostolic mission.', 29),
  (23, 'τάραχος', 'tarachos', 'G5017', 'Disturbance, commotion — the Ephesian uproar.', 30),
  (24, 'ἀργυροκόπος', 'argyrokopos', 'G695', 'Silversmith — craftsman-guild member dependent on idol-trade.', 31),
  (24, 'ναοὺς ἀργυροῦς', 'naous argyrous', 'G3485/G693', 'Silver shrines — miniature Artemis-temple souvenirs.', 32),
  (24, 'Ἀρτέμιδος', 'Artemidos', 'G735', 'Artemis/Diana — Ephesian fertility-goddess, Seven Wonders temple.', 33),
  (25, 'εὐπορία', 'euporia', 'G2142', 'Prosperity, livelihood — economic interest masquerading as piety.', 34),
  (26, 'μετέστησεν', 'metestēsen', 'G3179', 'Turned away, transferred — Paul''s converts moved from idols to Christ.', 35),
  (27, 'μεγαλειότητος', 'megaleiotētos', 'G3168', 'Majesty, magnificence — Artemis''s claimed grandeur.', 36),
  (29, 'θέατρον', 'theatron', 'G2302', 'Theatre — Ephesus''s 24,000-seat amphitheater.', 37),
  (31, 'Ἀσιαρχῶν', 'Asiarchōn', 'G775', 'Asiarchs — provincial officials supervising imperial cult.', 38),
  (32, 'ἐκκλησία', 'ekklēsia', 'G1577', 'Assembly — here the pagan mob (the same word used elsewhere for "church").', 39),
  (35, 'γραμματεὺς', 'grammateus', 'G1122', 'Town clerk — chief civic official of the Greek polis.', 40),
  (35, 'νεωκόρον', 'neōkoron', 'G3511', 'Temple-warden — honorary title for Ephesus''s guardianship of Artemis.', 41),
  (35, 'διοπετοῦς', 'diopetous', 'G1356', 'Fallen from Zeus — meteoric image worshipped as divine.', 42),
  (36, 'προπετὲς', 'propetes', 'G4312', 'Rash, reckless — clerk''s warning against hasty action.', 43),
  (37, 'ἱεροσύλους', 'hierosylous', 'G2417', 'Temple-robbers — apostles had not stolen sacred property.', 44)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Acts' AND c.chapter_number = 19 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

